var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"여기, 맥크레디 부인의 유언장 원본이에요. 확인해 보세요.","JPN":"これがマクレディー夫人の遺言状の原本です。ご確認ください。","ENG":"Here. This is the written will, the original one, that Mrs. MacCready made. See it for yourself.","TWN":"這裡，是麥克蕾蒂夫人的遺囑正本，請您確認一下。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"말도 안 돼......","JPN":"そんな……","ENG":"No way...","TWN":"不會吧……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아무리 학회에 심취했어도 그렇지 대체 무슨 생각이었던 거야?!","JPN":"いくら学会に心酔していたとしても、いったいどういうつもり！？","ENG":"What was she thinking? Did she really fall that deep into this nonsense?","TWN":"就算再熱衷於學會，也不能這麼做啊，她在想什麼啊？！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"충격이 크신 것 같네요. 잠시 쉰 다음에 계속 얘기하실래요?","JPN":"ショックが大きいようですね。しばらく休んでから話を続けましょうか？","ENG":"You seem shocked. Do you need some time for yourself?","TWN":"您似乎受到了很大的衝擊呢。我們稍微休息一下再繼續談吧？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"됐으니까 신경 쓰지 마세요!","JPN":"いいです、気にしないでください！","ENG":"Don't mind me. Go on!","TWN":"不了，不用管我！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"가문의 재산까지 가로챈 마당에 절 여기로 부른 이유가 뭐죠?","JPN":"マクレディー家の財産まで横取りしたうえで、私をここに呼んだ理由は何ですの？","ENG":"Then why did you want me here? The family assets weren't enough for you?","TWN":"既然妳連我家的財產都私吞了，為什麼還把我叫到這裡來？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"<color=#ffd34c>맥크레디 영지는 학회의 소굴이 됐다. 네 자리는 없으니 장례만 마치고 얌전히 사라져라.</color> 그런 뜻인가요?","JPN":"<color=#ffd34c>マクレディーの領地は学会の巣窟となった。お前の居場所は無いから、\\n葬儀が終わったらおとなしく姿を消せ。</color>ということですか？","ENG":"Did you want to tell me to my face that <color=#ffd34c>the MacCready Estate has fallen into the hands of the Society, and that you will leave nothing for me once the funeral is over</color>?","TWN":"<color=#ffd34c>麥克蕾蒂的領地已經變成學會的巢穴。這裡沒有妳的位置，葬禮結束後就乖乖消失吧</color>，是這個意思嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"......그렇지 않아요, 레지나 님.","JPN":"……違いますよ、レジーナ様。","ENG":"That's not the case, Miss Regina.","TWN":"……不是這樣的，蕾佳娜大人。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"저흰 이 유산을 받을 생각이 없어요. 상속을 포기하겠다는 신고서도 사전에 작성해 두었답니다.","JPN":"我々はこの遺産を受け取らないつもりです。相続を放棄するという書類も事前に作っておきました。","ENG":"We don't mean to keep the family assets to ourselves. The inheritance disclaimer has already been filled in.","TWN":"我們並不打算接受這份遺產，放棄繼承權的申請書我們也已經事先寫好了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"날인도 끝냈으니 그대로 변호사에게 보내기만 하면 돼요.","JPN":"捺印もしてあるので、そのまま弁護士に送れば手続きは終わりです。","ENG":"And the document has been signed as well. All you have to do is send it to the attorney.","TWN":"章也蓋了，所以就這樣交給律師就可以了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"뭐라고요? 어째서......?","JPN":"何ですって？　どうして……？","ENG":"Huh? But why?","TWN":"妳說什麼？怎麼會……？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"말씀드린 대로 레지나 님께서 한 번만 저희를 도와주셨으면 해요.","JPN":"お伝えしたとおり、レジーナ様には一度だけ我々を手伝っていただきたいのです。","ENG":"As said, we'd like for you to do something for us, just once.","TWN":"如我們剛才所說，蕾佳娜大人只要再幫我們一次就行了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"저희 부탁을 들어 주신다면 신고서는 지금 바로 레지나님께 드릴게요.","JPN":"我々の頼みを聞いていただけるのでしたら、書類はすぐにレジーナ様にお渡しします。","ENG":"If you decide to help us, the paper is yours.","TWN":"只要蕾佳娜大人願意聽我們的請求，我們可以現在就將申請書交給您。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"후우......","JPN":"ふう……","ENG":"*Sigh*","TWN":"呼……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"알겠어요. 일단 들어나 보죠. 대체 무슨 일 때문에 그러는지.","JPN":"分かりましたわ。とりあえず、お聞かせください。いったいどういうことなのかしら。","ENG":"Fine. I'll hear it. What is it about?","TWN":"我知道了。總之先聽聽看吧，究竟是什麼事情？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"전임 학회장...... 그러니까 어머님의 시신이 도난 당했어요.","JPN":"先代の学会長……つまり、お母様のご遺体が盗まれたのです。","ENG":"The former President's—your mother's body has been stolen.","TWN":"前任學會長……也就是您母親的遺體被人盜走了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......시, 시신이 도난 당해요?","JPN":"い、遺体が盗まれた……？","ENG":"S-stolen?","TWN":"……遺、遺體被盜了？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"대체 누가? 어째서?","JPN":"いったい誰が？　どうして？","ENG":"By whom? Why?","TWN":"到底是誰做的？為什麼？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"최근에 가문의 영지에 침입한 어떤 비밀 조직의 소행으로 추측하고 있어요.","JPN":"最近、マクレディー家の領地に侵入した、ある秘密組織の仕業だろうと推測しています。","ENG":"We suspect that it was a secret organization that has recently invaded the family estate.","TWN":"我們推測是最近入侵家族領地的某個秘密組織做的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그들은 학회의 오랜 적으로...... 자신들을 <color=#ffd34c>프리드웬 기관</color>이라고 부른답니다.","JPN":"彼らは学会の古くからの敵で……<color=#ffd34c>プリドウェン機関</color>と名乗っています。","ENG":"They're old enemies of the Society, and they call themselves the <color=#ffd34c>Prydwen Institution</color>.","TWN":"他們是學會長年的宿敵……並將自己稱為<color=#ffd34c>普利多溫機關</color>。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......정말 가지가지 하네요. 이 사이비 학회에 숙적도 있어요?","JPN":"……本当に笑えないですわね。このインチキ学会に宿敵までいるなんて。","ENG":"Give me a break. Now you have an archenemy?","TWN":"……還真是厲害呢。這個邪教學會也有宿敵喔？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그럼 경찰에는 알렸나요?","JPN":"それで、警察には連絡したのですか？","ENG":"Are the police aware of this?","TWN":"那妳報警了嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"아, 그건......","JPN":"ああ、それは……","ENG":"Ah, about that...","TWN":"啊，這個……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그건 내가 대신 설명해 줄게.","JPN":"それはアタシが代わりに説明してあげる。","ENG":"Let me explain on her behalf.","TWN":"這就由我來說明吧。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"에델이 날 고용한 이유 중 하나이기도 하거든.","JPN":"エデルが私を雇った理由の一つでもあるからさ。","ENG":"It was one of the reasons that Edel hired me.","TWN":"這也是艾瑟兒雇傭我的理由之一。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"리벳? 당신 여태 어디 있었어요?","JPN":"リベット？　今までどこにいたのですか？","ENG":"Rivet? Where have you been all along?","TWN":"里維？妳之前都到哪裡去了？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"언제쯤 둘이서 머리끄덩이 잡고 싸우나 숨어서 구경하고 있었지.","JPN":"いつになったら二人が掴み合いのケンカをするのかなって見物してたんだよ。","ENG":"I was hiding behind the curtain, waiting for the cat fight to start.","TWN":"因為不知道你們兩個什麼時候會互扯頭髮打起來，所以我就躲在旁邊看。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L38_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"근데 의외로 장단이 맞는 것 같아서 실망이야.","JPN":"でも、意外と気が合うみたいでガッカリ。","ENG":"I'm very disappointed that it seems you two are getting along.","TWN":"但你們似乎意外地談得來，真令人失望啊。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"천박한 기대감을 배신해서 참 미안하게 됐군요.","JPN":"薄っぺらい期待を裏切ってしまいましたわね。ごめんあそばせ。","ENG":"I'm very sorry that I've betrayed your ridiculous expectations.","TWN":"辜負了妳膚淺的期待，真是抱歉啊。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L40_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"뭐 어쨌든, 내가 전해 들은 대로라면 프리드웬 기관은 전투의 프로들이야.","JPN":"まあ、とにかく……アタシが聞いた話だと、プリドウェン機関は戦闘のプロ集団らしいよ。","ENG":"Anyway, from what I've heard, the Prydwen Institution is a group of professional combatants.","TWN":"不過總之，就我所聽說的，普利多溫機關是戰鬥的專業高手。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"숲에서 나타나는 하급 침식체도 처리 못하는 시골 경찰들이 어떻게 해볼 상대가 아니란 뜻이지.","JPN":"森に現れた下級侵食体も倒せない田舎の警察なんかに敵う相手じゃないってこと。","ENG":"The cops here can't even handle low-grade C.O.s. It's not likely that they'd be able to handle them.","TWN":"這裡的鄉下警察連樹林裡的低等侵蝕體都解決不了，是沒辦法對付他們的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그래서 베테랑 용병인 내가 숲을 돌아다니면서 녀석들의 행적을 쫓고 있었단 말씀!","JPN":"そこで、ベテラン傭兵であるアタシが森を歩き回って奴らの行方を追ってたってわけ！","ENG":"So I, a veteran mercenary, have been running around the forest looking for the Prydwen's traces.","TWN":"所以我這個老練的傭兵就在樹林間四處走動，追逐那些傢伙的行蹤啦！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그것 때문에 밤마다 나가서 침식체들을 상대하고 있었군요. 어쩐지......","JPN":"そのために夜な夜な出かけて侵食体と戦っていたのですわね。なるほど……","ENG":"That's why you've been out fighting C.O.s at night. That makes sense.","TWN":"妳每晚出去對付侵蝕體原來是為了這個啊，難怪……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"아닌데? 그냥 머리통 터트리는 맛이 좋아서 그런 건데?","JPN":"違うけど？　ただ侵食体の頭をぶった切るのが楽しくてさ。","ENG":"Nope. That's because I like bursting the heads of those C.O.s.","TWN":"不是啊？只是把侵蝕體的腦袋瓜打爆的感覺實在太棒了，我才這麼做的喔！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......그래요. 잠시나마 당신을 이해했다고 착각한 제가 바보죠.","JPN":"……そうですか。一瞬でもあなたを理解できたと勘違いした私が愚かでしたわ。","ENG":"Okay. I was a fool to think that I could understand you.","TWN":"……這樣喔。一瞬間誤以為理解妳的我真是太蠢了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그래서 어젯밤에야 겨우 녀석들의 아지트가 어디 있는지 알아냈어.","JPN":"で、昨晩ようやく奴らのアジトを突き止めたんだ。","ENG":"And last night, I finally found out where the Prydwen guys have been hiding all this time.","TWN":"就在昨晚，我終於知道那些傢伙的基地在哪了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"숲의 서쪽 끝이야. 한 판 붙으려면 놈들이 사라지기 전에 서둘러야 할걸.","JPN":"森の西端だよ。事を起こすなら、奴らが姿を消す前に急いだ方がいいと思うけど。","ENG":"It's in the western end of the forest. And you'd better hurry if you're looking to kick their butts before they leave.","TWN":"在森林西邊的盡頭，想要教訓他們的話，得趁他們消失前快點過去才行。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......정황은 대략 파악되네요.","JPN":"……状況は大体把握できました。","ENG":"I get the situation. At least a glimpse of it.","TWN":"……情況我大概都明白了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"알겠습니다. 어머니의 시신을 수습하는 일에 한해 당신들과 협력하겠어요.","JPN":"わかりましたわ。お母様の遺体を取り戻すことに限り、あなた方と協力いたします。","ENG":"Fine. I'll help you, just until I retrieve my mother's body.","TWN":"我知道了。就看在找回母親遺體的份上，這次我會和你們合作。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"정말인가요?","JPN":"本当ですか？","ENG":"Really?","TWN":"真的嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"후후, 레지나 님께서 도와 주신다니 정말 기뻐요.","JPN":"ふふ、レジーナ様に協力していただけるなんて嬉しいですね。","ENG":"It's so awesome that you're helping us, Miss Regina!","TWN":"呵呵，蕾佳娜大人竟然願意幫助我們，真是令人高興。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"기, 기쁘긴 뭐가 기뻐요? 당신은 약속이나 잘 지키도록 해요!","JPN":"う、嬉しいって何がですか？　あなたは約束を守ることだけ考えていてください！","ENG":"W-what are you smiling for? You make sure to keep your promise!","TWN":"有、有什麼好高興的？妳給我好好遵守約定就是了！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그럼요. 걱정 마세요, 레지나 님.","JPN":"もちろんです。ご心配なく、レジーナ様。","ENG":"Of course. Don't worry, Miss Regina.","TWN":"當然了。請不用擔心，蕾佳娜大人。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"저희는 약속을 어기지 않는답니다.","JPN":"我々は決して約束を破りません。","ENG":"We don't break promises.","TWN":"我們不會打破約定的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};